INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cal-com', 'cal-com', 'cal.com', 'https://cal.com', 'Cal.com', 'Open source scheduling infrastructure.', 'The interesting move was not cloning Calendly in public. It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves. That is a sharper bet than generic booking software. Cal.com is selling control, not just calendar pages.', 4, 'Open source done right', 'SaaS', 'Series A', '$25M', 2021, '30-50', 'San Francisco', 'US', 'scheduling,open source,calendar,productivity', 'Dick Costolo, Joseph Jacks (OSS Capital), Peer Richelsen', '{"github": "https://github.com/calcom/cal.com", "twitter": "https://x.com/calabordar", "linkedin": "https://linkedin.com/company/cal-com"}', 0, 'cal-com.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cursor', 'cursor', 'cursor.com', 'https://cursor.com', 'Cursor', 'The AI-first code editor.', 'The right bet was not copilot-inside-VSCode, but an editor rebuilt around the model. Tab completion, inline diffs, and cmd-K feel native rather than bolted on. By forking VS Code instead of starting from scratch, Cursor kept the muscle memory and changed the center of gravity. That is why it feels sticky instead of merely novel.', 5, 'Changed how developers write code', 'AI / ML', 'Series A', '$60M', 2022, '50-100', 'San Francisco', 'US', 'ai,code editor,developer tools,productivity', 'Andreessen Horowitz, Thrive Capital, OpenAI Startup Fund', '{"github": "https://github.com/getcursor", "twitter": "https://x.com/cursor_ai", "linkedin": "https://linkedin.com/company/cursor-ai"}', 1, 'cursor.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-eleven-labs', 'eleven-labs', 'elevenlabs.io', 'https://elevenlabs.io', 'ElevenLabs', 'AI voice generation and speech synthesis platform.', 'The surprising thing is not that voice cloning works. It is that 30 seconds of audio can already get you something commercially usable. ElevenLabs is betting this becomes infrastructure for dubbing, audiobooks, and accessibility, not just a viral demo. That is a narrower and more durable business than AI voice as spectacle.', 4, 'Voice AI that actually sounds human', 'AI / ML', 'Series B', '$80M', 2022, '50-100', 'New York', 'US', 'voice ai,speech synthesis,text to speech,artificial intelligence', 'Andreessen Horowitz, Nat Friedman, Daniel Gross', '{"github": "https://github.com/elevenlabs", "twitter": "https://x.com/elevenlabsio", "linkedin": "https://linkedin.com/company/elevenlabs"}', 0, 'eleven-labs.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-linear', 'linear', 'linear.app', 'https://linear.app', 'Linear', 'Issue tracking built for modern software teams.', 'Someone finally rebuilt project management for teams that live on the keyboard. Keyboard shortcuts, a stripped-back issue flow, and an interface that stays out of the way make it feel closer to an editor than Jira. In a market full of feature-bloated software, Linear chose speed and restraint. That trade only works if you are willing to say no more often than your competitors.', 5, 'Defined a new standard for dev tools', 'DevTools', 'Series C', '$82M', 2019, '50-100', 'San Francisco', 'US', 'project management,issue tracking,developer tools,productivity', 'Sequoia Capital, 01 Advisors, SV Angel', '{"github": "https://github.com/linear", "twitter": "https://x.com/linear", "linkedin": "https://linkedin.com/company/linear"}', 1, 'linear.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-perplexity', 'perplexity', 'perplexity.ai', 'https://perplexity.ai', 'Perplexity', 'AI-powered answer engine that searches the web.', 'Answer-first search should have existed years ago. Perplexity makes the core interaction brutally simple: ask a question, get a synthesized answer with sources, not ten blue links and ad clutter. That is a sharp product bet against the browsing-heavy search interface. The open question is whether that habit expands beyond power users.', 5, 'The Google killer that might actually be', 'AI / ML', 'Series B', '$73.6M', 2022, '100-200', 'San Francisco', 'US', 'ai search,answer engine,web search,artificial intelligence', 'IVP, NEA, Databricks Ventures, Jeff Bezos', '{"twitter": "https://x.com/perabordar", "linkedin": "https://linkedin.com/company/perplexity-ai"}', 1, 'perplexity.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-resend', 'resend', 'resend.com', 'https://resend.com', 'Resend', 'Email API for developers. Beautiful, simple, reliable.', 'Transactional email used to feel like plumbing you tolerated, not a product you enjoyed. Resend changed that with a cleaner API surface and React Email as a companion project. That pairing reveals the bet: email delivery and email design should live in the same developer workflow. It feels closer to Stripe-grade DX than legacy SMTP tooling.', 4, 'DX that makes you jealous', 'DevTools', 'Seed', '$3M', 2022, '10-30', 'San Francisco', 'US', 'email,api,developer tools,transactional email', 'Y Combinator, SV Angel, Dylan Field', '{"github": "https://github.com/resend", "twitter": "https://x.com/resabordar", "linkedin": "https://linkedin.com/company/resend"}', 1, 'resend.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'The clever part is not calling itself an open-source Firebase alternative. The clever part is turning Postgres into the center of an entire developer stack: auth, storage, realtime, and edge functions. Where most backend platforms hide the database behind abstractions, Supabase leans into it. That makes the product more opinionated and easier to reason about than a generic backend cloud.', 4, 'Postgres as a platform', 'DevTools', 'Series B', '$80M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase"}', 0, 'supabase.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Putting running code inside a social feed sounds gimmicky until you try it. Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks. That is a real bet against repo-first developer tooling. It feels closer to what Gists wanted to be than another serverless dashboard.', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town"}', 0, 'val-town.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = exclude